orchestrator.register_nested_chats(
    chat_queue=[
        # Step 1: research the task
        {
            "sender": research_executor,
            "recipient": research_specialist,
            "message": lambda sender, recipient, context: context.get("last_message", {}).get("content", ""),
            "max_turns": 4,
            "summary_method": "last_msg",
        },
        # Step 2: implement based on research (summary carries forward)
        {
            "sender": code_executor,
            "recipient": code_specialist,
            "message": "Implement what was researched. Use the context provided.",
            "carryover": True,    # receives research summary from step 1
            "max_turns": 6,
            "summary_method": "reflection_with_llm",
        },
    ],
    trigger=lambda sender: "implement" in (
        sender.last_message(orchestrator) or {}
    ).get("content", "").lower(),
)

# Option 1: static string
{
    "message": "Implement a sorting algorithm in Python.",
}

# Option 2: callable — (sender, recipient, context) -> str
# context["last_message"] is the message that triggered the nested chat
{
    "message": lambda sender, recipient, context: (
        f"Task from outer conversation: {context['last_message'].get('content', '')}"
    ),
}

# Option 3: dict — passed as a full message object
{
    "message": {"role": "user", "content": "Implement the algorithm described above."},
}

# Custom summary function — extract only the code block from the inner chat
def extract_code_summary(chat_result) -> str:
    messages = chat_result.chat_history
    # Find last code block in any message
    for msg in reversed(messages):
        content = msg.get("content", "")
        if "```python" in content:
            start = content.find("```python") + len("```python\n")
            end = content.find("```", start)
            return content[start:end].strip()
    return messages[-1].get("content", "") if messages else ""

chat_spec = {
    "sender": code_executor,
    "recipient": code_specialist,
    "message": "Implement merge sort.",
    "max_turns": 6,
    "summary_method": extract_code_summary,  # custom summary
}
